import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';

export interface MaterialDto {
  id: string;
  code: string;
  name: string;
  unitCode?: string;
  standardCost?: number;
  accountCode?: string;
  isActive?: boolean;
}

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const materialApi = {
  searchMaterials: async (params: { search?: string; page: number; pageSize: number }) => {
    const qs = buildQs({
      search: params.search,
      page: params.page,
      pageSize: params.pageSize,
      isActive: true,
    });
    const res = await apiClient.get<BffResponse<MaterialDto[]>>(`/master/materials?${qs}`);
    const data = unwrap(res) ?? [];
    const totalPages = Math.max(1, Math.ceil(data.length / params.pageSize));
    const start = (params.page - 1) * params.pageSize;
    return {
      items: data.slice(start, start + params.pageSize),
      page: params.page,
      totalPages,
    };
  },
};
