import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { sxService } from '../../../services/sx/sxService';
import type { BomLineDto } from '../../../services/sx/models';
import { DocumentFormHeader } from '../../../components/layout';
import { LineMaterialSearchCell, MaterialLineTableHeaders } from '../../../components/search';
import df from '../../../styles/documentForm.module.css';

const emptyLine: BomLineDto = { materialCode: '', materialName: '', unitCode: 'CAI', quantity: 1 };

const emptyForm = {
  productCode: '',
  unitCode: 'CAI',
  quantity: 1,
  effectiveFrom: new Date().toISOString().slice(0, 10),
  effectiveTo: '',
  isActive: true,
  lines: [{ ...emptyLine }],
};

const BomFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();

  const [form, setForm] = useState(emptyForm);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getBom(id)
        .then(b => {
          if (!cancelled) {
            setForm({
              productCode: b.productCode,
              unitCode: b.unitCode,
              quantity: b.quantity,
              effectiveFrom: b.effectiveFrom.slice(0, 10),
              effectiveTo: b.effectiveTo?.slice(0, 10) ?? '',
              isActive: b.isActive,
              lines: b.lines.length > 0 ? b.lines : [{ ...emptyLine }],
            });
          }
        })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Không tải BOM', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const setLine = (idx: number, field: keyof BomLineDto, value: string | number) => {
    setForm(prev => {
      const lines = [...prev.lines];
      lines[idx] = { ...lines[idx], [field]: value };
      return { ...prev, lines };
    });
  };

  const addLine = () => setForm(prev => ({ ...prev, lines: [...prev.lines, { ...emptyLine }] }));
  const removeLine = (idx: number) => {
    if (form.lines.length <= 1) {
      dispatch(addToast({ message: 'Phải có ít nhất 1 dòng', type: 'warning' }));
      return;
    }
    setForm(prev => ({ ...prev, lines: prev.lines.filter((_, i) => i !== idx) }));
  };

  const handleSave = async () => {
    if (!form.productCode.trim()) {
      dispatch(addToast({ message: 'Vui lòng nhập mã sản phẩm', type: 'error' }));
      return;
    }
    const lines = form.lines.filter(l => l.materialCode.trim());
    if (lines.length === 0) {
      dispatch(addToast({ message: 'BOM cần ít nhất 1 dòng vật tư', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      if (isEdit && id) {
        await sxService.updateBom(id, {
          quantity: Number(form.quantity),
          effectiveFrom: form.effectiveFrom,
          effectiveTo: form.effectiveTo || undefined,
          isActive: form.isActive,
          lines,
        });
        dispatch(addToast({ message: 'Cập nhật BOM thành công', type: 'success' }));
      } else {
        await sxService.createBom({
          productCode: form.productCode.trim(),
          unitCode: form.unitCode.trim() || 'CAI',
          quantity: Number(form.quantity),
          effectiveFrom: form.effectiveFrom,
          effectiveTo: form.effectiveTo || undefined,
          lines,
        });
        dispatch(addToast({ message: 'Tạo BOM thành công', type: 'success' }));
      }
      navigate('/sx/bom');
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/sx/bom')}
        title={isEdit ? 'Sửa BOM' : 'Tạo BOM'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo BOM"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Sản phẩm</h2>
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Mã SP *</label><Input value={form.productCode} onChange={e => setForm(p => ({ ...p, productCode: e.target.value }))} disabled={isEdit} /></div>
          <div className={df.field}><label className={df.label}>ĐVT</label><Input value={form.unitCode} onChange={e => setForm(p => ({ ...p, unitCode: e.target.value }))} disabled={isEdit} /></div>
          <div className={df.field}><label className={df.label}>SL chuẩn</label><Input type="number" min={0.01} step={0.01} value={String(form.quantity)} onChange={e => setForm(p => ({ ...p, quantity: Number(e.target.value) }))} /></div>
          <div className={df.field}><label className={df.label}>Hiệu lực từ</label><Input type="date" value={form.effectiveFrom} onChange={e => setForm(p => ({ ...p, effectiveFrom: e.target.value }))} /></div>
        </div>
        {isEdit && (
          <div className={df.row4}>
            <div className={df.field}>
              <label className={df.label}>Hoạt động</label>
              <Select
                value={form.isActive ? 'true' : 'false'}
                onChange={e => setForm(p => ({ ...p, isActive: e.target.value === 'true' }))}
                options={[
                  { value: 'true', label: 'Khả dụng' },
                  { value: 'false', label: 'Ngưng' },
                ]}
              />
            </div>
          </div>
        )}
      </div>
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Vật tư / NVL</h2>
        <div className={df.tableWrapper}>
          <table className={df.linesTable}>
            <thead>
              <tr><MaterialLineTableHeaders /><th>ĐVT</th><th className={df.thAmount}>SL</th><th className={df.thDel} /></tr>
            </thead>
            <tbody>
              {form.lines.map((line, idx) => (
                <tr key={idx}>
                  <LineMaterialSearchCell
                    materialCode={line.materialCode}
                    materialName={line.materialName ?? ''}
                    onSelect={m => {
                      setForm(prev => {
                        const lines = [...prev.lines];
                        lines[idx] = {
                          ...lines[idx],
                          materialCode: m.code,
                          materialName: m.name,
                          unitCode: m.unitCode ?? lines[idx].unitCode,
                        };
                        return { ...prev, lines };
                      });
                    }}
                    onClear={() => {
                      setForm(prev => {
                        const lines = [...prev.lines];
                        lines[idx] = { ...lines[idx], materialCode: '', materialName: '' };
                        return { ...prev, lines };
                      });
                    }}
                  />
                  <td><Input value={line.unitCode} onChange={e => setLine(idx, 'unitCode', e.target.value)} /></td>
                  <td><Input type="number" min={0.01} value={String(line.quantity)} onChange={e => setLine(idx, 'quantity', Number(e.target.value))} /></td>
                  <td><button type="button" className={df.btnDeleteLine} onClick={() => removeLine(idx)} title="Xóa dòng">×</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <button type="button" className={df.btnAddLine} onClick={addLine}>+ Thêm dòng</button>
      </div>
    </div>
  );
};

export default BomFormPage;
